-- MIGRATION: 20260718100000_master_schema_skills.sql-- Descripción: Script maestro que crea TODAS las tablas necesarias para soportar las 333 skills-- de las 15 categorías de Learn Up. Se usa IF NOT EXISTS para no pisar datos existentes.--------------------------------------------------------------------------------- 1. EXTENSIONES BÁSICAS-------------------------------------------------------------------------------CREATE EXTENSION IF NOT EXISTS "uuid-ossp";--------------------------------------------------------------------------------- 2. CATEGORÍAS 1 & 2: CALENDARIO Y SOCIAL (Complementos)--------------------------------------------------------------------------------- Chat PollsCREATE TABLE IF NOT EXISTS public.chat_polls (    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),    room_id UUID NOT NULL REFERENCES public.chat_rooms(id) ON DELETE CASCADE,    creator_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,    question TEXT NOT NULL,    options JSONB NOT NULL, -- Array of strings    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),    expires_at TIMESTAMPTZ);ALTER TABLE public.chat_polls ENABLE ROW LEVEL SECURITY;DROP POLICY IF EXISTS "" ON ;CREATE POLICY "Users can view polls in their rooms" ON public.chat_polls FOR SELECT USING (EXISTS (SELECT 1 FROM public.room_members rm WHERE rm.room_id = chat_polls.room_id AND rm.user_id = auth.uid()));DROP POLICY IF EXISTS "" ON ;CREATE POLICY "Users can create polls in their rooms" ON public.chat_polls FOR INSERT WITH CHECK (EXISTS (SELECT 1 FROM public.room_members rm WHERE rm.room_id = chat_polls.room_id AND rm.user_id = auth.uid()));CREATE TABLE IF NOT EXISTS public.chat_poll_votes (    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),    poll_id UUID NOT NULL REFERENCES public.chat_polls(id) ON DELETE CASCADE,    user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,    option_index INTEGER NOT NULL,    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),    UNIQUE(poll_id, user_id));ALTER TABLE public.chat_poll_votes ENABLE ROW LEVEL SECURITY;DROP POLICY IF EXISTS "" ON ;CREATE POLICY "Users can view votes in their rooms" ON public.chat_poll_votes FOR SELECT USING (EXISTS (SELECT 1 FROM public.chat_polls p JOIN public.room_members rm ON rm.room_id = p.room_id WHERE p.id = chat_poll_votes.poll_id AND rm.user_id = auth.uid()));DROP POLICY IF EXISTS "" ON ;CREATE POLICY "Users can vote in polls in their rooms" ON public.chat_poll_votes FOR INSERT WITH CHECK (user_id = auth.uid());--------------------------------------------------------------------------------- 3. CATEGORÍA 3: BIBLIOTECA-------------------------------------------------------------------------------CREATE TABLE IF NOT EXISTS public.library_items (    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),    user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,    title TEXT NOT NULL,    item_type TEXT NOT NULL CHECK (item_type IN ('pdf', 'video', 'link', 'document')),    url TEXT,    content TEXT,    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),    archived BOOLEAN DEFAULT FALSE);ALTER TABLE public.library_items ENABLE ROW LEVEL SECURITY;DROP POLICY IF EXISTS "" ON ;CREATE POLICY "Users manage their own library" ON public.library_items FOR ALL USING (user_id = auth.uid());--------------------------------------------------------------------------------- 4. CATEGORÍAS 5 & 6: GENERACIÓN Y MULTIMEDIA-------------------------------------------------------------------------------CREATE TABLE IF NOT EXISTS public.generated_content (    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),    user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,    content_type TEXT NOT NULL, -- 'essay', 'study_guide', 'summary', 'presentation'    title TEXT,    body TEXT,    metadata JSONB,    created_at TIMESTAMPTZ NOT NULL DEFAULT now());ALTER TABLE public.generated_content ENABLE ROW LEVEL SECURITY;DROP POLICY IF EXISTS "" ON ;CREATE POLICY "Users manage their generated content" ON public.generated_content FOR ALL USING (user_id = auth.uid());CREATE TABLE IF NOT EXISTS public.user_media (    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),    user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,    media_type TEXT NOT NULL, -- 'image', 'video', 'audio'    source_type TEXT NOT NULL, -- 'generated', 'uploaded', 'youtube'    url TEXT NOT NULL,    analysis_result TEXT,    created_at TIMESTAMPTZ NOT NULL DEFAULT now());ALTER TABLE public.user_media ENABLE ROW LEVEL SECURITY;DROP POLICY IF EXISTS "" ON ;CREATE POLICY "Users manage their media" ON public.user_media FOR ALL USING (user_id = auth.uid());--------------------------------------------------------------------------------- 5. CATEGORÍA 7: INVESTIGACIÓN-------------------------------------------------------------------------------CREATE TABLE IF NOT EXISTS public.saved_sources (    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),    user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,    title TEXT NOT NULL,    url TEXT NOT NULL,    source_type TEXT, -- 'academic_paper', 'web_article', 'wikipedia'    summary TEXT,    created_at TIMESTAMPTZ NOT NULL DEFAULT now());ALTER TABLE public.saved_sources ENABLE ROW LEVEL SECURITY;DROP POLICY IF EXISTS "" ON ;CREATE POLICY "Users manage their saved sources" ON public.saved_sources FOR ALL USING (user_id = auth.uid());--------------------------------------------------------------------------------- 6. CATEGORÍAS 8 & 9: PERFIL Y ANÁLISIS-------------------------------------------------------------------------------CREATE TABLE IF NOT EXISTS public.friendships (    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),    requester_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,    addressee_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,    status TEXT NOT NULL DEFAULT 'pending' CHECK (status IN ('pending', 'accepted', 'rejected', 'blocked')),    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),    UNIQUE(requester_id, addressee_id));ALTER TABLE public.friendships ENABLE ROW LEVEL SECURITY;DROP POLICY IF EXISTS "" ON ;CREATE POLICY "Users can view friendships" ON public.friendships FOR SELECT USING (auth.uid() = requester_id OR auth.uid() = addressee_id);DROP POLICY IF EXISTS "" ON ;CREATE POLICY "Users can insert friendships" ON public.friendships FOR INSERT WITH CHECK (auth.uid() = requester_id);DROP POLICY IF EXISTS "" ON ;CREATE POLICY "Users can update their friendships" ON public.friendships FOR UPDATE USING (auth.uid() = requester_id OR auth.uid() = addressee_id);DROP POLICY IF EXISTS "" ON ;CREATE POLICY "Users can delete their friendships" ON public.friendships FOR DELETE USING (auth.uid() = requester_id OR auth.uid() = addressee_id);CREATE TABLE IF NOT EXISTS public.user_achievements (    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),    user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,    achievement_key TEXT NOT NULL,    unlocked_at TIMESTAMPTZ NOT NULL DEFAULT now(),    UNIQUE(user_id, achievement_key));ALTER TABLE public.user_achievements ENABLE ROW LEVEL SECURITY;DROP POLICY IF EXISTS "" ON ;CREATE POLICY "Users can view their achievements" ON public.user_achievements FOR SELECT USING (user_id = auth.uid());DROP POLICY IF EXISTS "" ON ;CREATE POLICY "Users can unlock achievements" ON public.user_achievements FOR INSERT WITH CHECK (user_id = auth.uid());--------------------------------------------------------------------------------- 7. CATEGORÍAS 10-15: EDUCACIÓN ESPECIALIZADA (Exámenes, Planes, Flashcards)-------------------------------------------------------------------------------CREATE TABLE IF NOT EXISTS public.study_plans (    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),    user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,    subject TEXT NOT NULL,    plan_data JSONB NOT NULL,    created_at TIMESTAMPTZ NOT NULL DEFAULT now());ALTER TABLE public.study_plans ENABLE ROW LEVEL SECURITY;DROP POLICY IF EXISTS "" ON ;CREATE POLICY "Users manage their study plans" ON public.study_plans FOR ALL USING (user_id = auth.uid());CREATE TABLE IF NOT EXISTS public.flashcard_decks (    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),    user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,    title TEXT NOT NULL,    created_at TIMESTAMPTZ NOT NULL DEFAULT now());ALTER TABLE public.flashcard_decks ENABLE ROW LEVEL SECURITY;DROP POLICY IF EXISTS "" ON ;CREATE POLICY "Users manage their flashcard decks" ON public.flashcard_decks FOR ALL USING (user_id = auth.uid());CREATE TABLE IF NOT EXISTS public.flashcard_cards (    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),    deck_id UUID NOT NULL REFERENCES public.flashcard_decks(id) ON DELETE CASCADE,    front_text TEXT NOT NULL,    back_text TEXT NOT NULL,    next_review TIMESTAMPTZ NOT NULL DEFAULT now(),    interval_days INTEGER NOT NULL DEFAULT 0,    ease_factor REAL NOT NULL DEFAULT 2.5,    created_at TIMESTAMPTZ NOT NULL DEFAULT now());ALTER TABLE public.flashcard_cards ENABLE ROW LEVEL SECURITY;DROP POLICY IF EXISTS "" ON ;CREATE POLICY "Users manage their flashcards" ON public.flashcard_cards FOR ALL USING (EXISTS (SELECT 1 FROM public.flashcard_decks fd WHERE fd.id = flashcard_cards.deck_id AND fd.user_id = auth.uid()));CREATE TABLE IF NOT EXISTS public.exams (    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),    user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,    title TEXT NOT NULL,    score INTEGER,    max_score INTEGER,    completed_at TIMESTAMPTZ,    created_at TIMESTAMPTZ NOT NULL DEFAULT now());ALTER TABLE public.exams ENABLE ROW LEVEL SECURITY;DROP POLICY IF EXISTS "" ON ;CREATE POLICY "Users manage their exams" ON public.exams FOR ALL USING (user_id = auth.uid());CREATE TABLE IF NOT EXISTS public.exam_questions (    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),    exam_id UUID NOT NULL REFERENCES public.exams(id) ON DELETE CASCADE,    question_text TEXT NOT NULL,    options JSONB,    correct_answer TEXT NOT NULL,    user_answer TEXT,    is_correct BOOLEAN,    created_at TIMESTAMPTZ NOT NULL DEFAULT now());ALTER TABLE public.exam_questions ENABLE ROW LEVEL SECURITY;DROP POLICY IF EXISTS "" ON ;CREATE POLICY "Users manage their exam questions" ON public.exam_questions FOR ALL USING (EXISTS (SELECT 1 FROM public.exams e WHERE e.id = exam_questions.exam_id AND e.user_id = auth.uid()));